head.script:
scwin.loginDTO = {};
scwin.userClsCd = "";
scwin.loginClntNo = "";
scwin.loginClntNm = "";
scwin.loUpperLobranCd = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.loginDTO = $c.data.getMemInfo();
    scwin.userClsCd = scwin.loginDTO.userClsCd || "";
    scwin.loginClntNo = scwin.loginDTO.clntNo || "";
    scwin.loginClntNm = scwin.loginDTO.clntNm || "";
    scwin.loUpperLobranCd = scwin.loginDTO.loUpperLobranCd || "";

    let param = [
        {
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retriveLobranCodeTotalList",
            compID: "gr_retrieveusablevehiclespresent:assgnLobranCd"
        },
        {
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retriveLobranCodeTotalList",
            compID: "gr_retrieveusablevehiclespresent:regLobranCd"
        }
    ];

    $c.data.setGauceUtil(param);

    let codeOptions = [
        { grpCd: "ZZ202", compID: "lc_con_cartype", opt: { "upperCd": "LV" } },
        { grpCd: "ZZ210", compID: "lc_con_cartype", opt: { "upperCd": "TL" } },
        { grpCd: "ZZ303", compID: "lc_con_currSts" }
    ];

    $c.data.setCommonCode(codeOptions, function () {
        dlt_commonCodeZZ202.insertRow(0);
        dlt_commonCodeZZ202.setCellData(0, "cd", "");
        dlt_commonCodeZZ202.setCellData(0, "cdNm", "전체");

        dlt_commonCodeZZ210.insertRow(0);
        dlt_commonCodeZZ210.setCellData(0, "cd", "");
        dlt_commonCodeZZ210.setCellData(0, "cdNm", "전체");

        dlt_commonCodeZZ303.insertRow(0);
        dlt_commonCodeZZ303.setCellData(0, "cd", "");
        dlt_commonCodeZZ303.setCellData(0, "cdNm", "전체");
    });

    $c.sbm.execute(sbm_co_ds_regLobranCd);
    $c.sbm.execute(sbm_co_ds_assgnLobranCd);

    scwin.f_comboValueCargo();
};

scwin.onUdcCompleted = function () {
    rd_con_cls.setValue("0");
    lc_mbssysVehclYn.setSelectedIndex(0);

    $c.gus.cfDisableObjects([lc_mbssysVehclYn]);

    if (scwin.userClsCd == "02") {
        ed_con_coCls.setValue(scwin.loginClntNo);
        ed_con_coClsNm.setValue(scwin.loginClntNm);
        ed_con_coCls.setReadOnly(true);
        ed_con_coClsNm.setDisabled(true);
        popupClnt.setDisabled(true);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function (e) {
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function (e) {
    rd_con_cls.setValue("0");
    lc_con_assgnLobranCd.setSelectedIndex(0);
    lc_con_cartype.setSelectedIndex(0);
    lc_con_regLobranCd.setSelectedIndex(0);
    lc_con_currSts.setSelectedIndex(0);
    lc_con_cargoClsCd.setSelectedIndex(0);
    lc_con_coCls.setSelectedIndex(0);
    lc_mbssysVehclYn.setSelectedIndex(0);

    if (scwin.userClsCd != "02") {
        $c.gus.cfInitObjects([ed_con_coCls, ed_con_coClsNm, ed_con_vehclCd, ed_con_vehclNm]);
    } else if (scwin.userClsCd == "02") {
        $c.gus.cfInitObjects([ed_con_vehclCd, ed_con_vehclNm]);
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            udc_comCode2.cfCommonPopUp(function (rtnList) {
                $c.gus.cfSetReturnValue(rtnList, ed_con_coClsNm, ed_con_coCls);
            }, pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "협력업체조회,협력업체코드,협력업체명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
        case 2:
            udc_comCode.cfCommonPopUp(function (rtnList) {
                $c.gus.cfSetReturnValue(rtnList, ed_con_vehclNm, ed_con_vehclCd);
            }, pName					// 화면에서의 ??? Code Element의	Value
                , pCode				    // 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , "2"                    // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서	
                , "180,145"              // 보여주는 각 컬럼들의 폭	
                , "3,4,5,6,7,8,9,10"  	// 컬럼중에서 숨기는	컬럼 지정	
                , "LO,1"					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "차량번호조회,차량번호,차량단축코드"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
    }
};

//-------------------------------------------------------------------------
// function name : f_comboValue
// function desc : 운송화물 구분 검색
//-------------------------------------------------------------------------
scwin.f_comboValueCargo = async function () {
    let sbm_co_ds_combo1 = {};
    sbm_co_ds_combo1.action = "/cm.zz.RetrieveComboCMD.do?sysCd=EquipmentNonUsableEBC&queryId=retriveCargoCodeListCombo";

    let e = await $c.sbm.executeDynamic(sbm_co_ds_combo1);

    co_ds_combo1.setJSON(e.responseJSON.GAUCE);
};

//-------------------------------------------------------------------------
// 업체구분 콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveSecondCoCls = async function (param1) {
    let sbm_co_ds_combo2 = {};
    sbm_co_ds_combo2.action = "/cm.zz.RetrieveComboCMD.do?sysCd=EquipmentNonUsableEBC&queryId=retrivecCoClsComboCodeList&param1=" + param1;

    let e = await $c.sbm.executeDynamic(sbm_co_ds_combo2);

    co_ds_combo2.setJSON(e.responseJSON.GAUCE);

    co_ds_combo2.insertRow(0);
    co_ds_combo2.setCellData(0, "name", "전체");
    co_ds_combo2.setCellData(0, "code", "");

    lc_con_coCls.setSelectedIndex(0);
};

//-------------------------------------------------------------------------
// List 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel = function () {
    let options = {
        fileName: "지점별 차량 샤시 보유현황" + ".xlsx",
        sheetName: "지점별 차량 샤시 보유현황"
    }

    $c.data.downloadGridViewExcel(gr_retrieveusablevehiclespresent, options);
};

scwin.rd_con_cls_onchange = async function (info) {
    if (rd_con_cls.getValue() == "0") {
        lc_con_cartype.setNodeSet("data:dlt_commonCodeZZ202", "cdNm", "cd");
    } else if (rd_con_cls.getValue() == "1") {
        lc_con_cartype.setNodeSet("data:dlt_commonCodeZZ210", "cdNm", "cd");
    }
};

scwin.lc_con_cargoClsCd_onchange = function (info) {
    scwin.f_RetrieveSecondCoCls(lc_con_cargoClsCd.getValue());
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    let rowCnt = dlt_retrieveusablevehiclespresent.getRowCount();

    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg("조회결과가 존재하지 않습니다.");
    }

    totalRows.setValue(rowCnt);
};


scwin.sbm_co_ds_assgnLobranCd_submitdone = function (e) {
    co_ds_assgnLobranCd.insertRow(0);
    co_ds_assgnLobranCd.setCellData(0, "lobranCd", "");
    co_ds_assgnLobranCd.setCellData(0, "lobranNm", "전체");

    lc_con_assgnLobranCd.setValue(scwin.loUpperLobranCd);
};

scwin.sbm_co_ds_regLobranCd_submitdone = function (e) {
    co_ds_regLobranCd.insertRow(0);
    co_ds_regLobranCd.setCellData(0, "lobranCd", "");
    co_ds_regLobranCd.setCellData(0, "lobranNm", "전체");

    lc_con_regLobranCd.setValue(scwin.loUpperLobranCd);
};

scwin.lc_con_coCls_onchange = function (info) {
    let strValue = lc_con_coCls.getValue();

    lc_mbssysVehclYn.setSelectedIndex(0);

    if (strValue == "WW" || strValue == "YF" || strValue == "YO" || strValue == "YY") {
        $c.gus.cfEnableObjects([lc_mbssysVehclYn]);
    } else {
        $c.gus.cfDisableObjects([lc_mbssysVehclYn]);
    }
};

scwin.udc_comCode2_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_con_coCls, ed_con_coClsNm, 1);
};

scwin.udc_comCode_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_con_vehclCd, ed_con_vehclNm, 2);
};

scwin.udc_comCode_onblurNameEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_con_vehclNm, ed_con_vehclCd, 2, false);
};

scwin.udc_comCode_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_con_vehclCd.getValue(), ed_con_vehclNm.getValue(), "T", "T");
};

scwin.udc_comCode2_onblurNameEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_con_coClsNm, ed_con_coCls, 1, false);
};

scwin.udc_comCode2_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_con_coCls.getValue(), ed_con_coClsNm.getValue(), "T", "T");
};
